$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_7fc98b2d0bfc8906aad1c54f22465ab7'] = 'Se recomienda habilitar esta función solo por unos minutos, ya que puede ocurrir un registro excesivo. Se desactivará automáticamente después de 10 minutos para evitar archivos de registro grandes.';
