$_MODULE['<{facebookconversiontrackingplus}prestashop>facebookconversiontrackingplus_7c4bbfbb3c9a8159e5681792fecdd161'] = 'Esto dará más tiempo a Facebook para enviar la respuesta y permitirá al servidor aumentar el tiempo mientras espera.';
